class ListNode {
  constructor(val = 0, next = null) { this.val = val; this.next = next; }
}
function buildList(nums) {
  const dummy = new ListNode(0); let cur = dummy;
  for (const n of nums) { cur.next = new ListNode(n); cur = cur.next; }
  return dummy.next;
}
function listToArr(head) {
  const res = []; while (head) { res.push(head.val); head = head.next; } return res;
}
function removeNthFromEnd(head, n) {
    const node = buildList(head);
    const dummy = new ListNode(0);
    dummy.next = node;
    let fast = dummy, slow = dummy;
    for (let i = 0; i <= n; i++) fast = fast.next;
    while (fast) { fast = fast.next; slow = slow.next; }
    slow.next = slow.next.next;
    return listToArr(dummy.next);
}
